<script setup lang="ts">
const props = defineProps({
  id: {
    type: String,
    default: "",
  },
  label: {
    type: String,
    default: "",
  },
  color: {
    type: String as () =>  'primary' | 'success' | 'info' | 'warning' |'error',
    default: 'primary'
  }
});

const emit = defineEmits(["on-click"]);

const textColor = computed(() => {
  return `text-${props.color}-500 hover:text-${props.color}-400`
})
</script>

<template>
  <a
    :id="props.id"
    class="text-xs inline-flex items-center font-semibold cursor-pointer space-x-2 "
    :class="textColor"
    @click="emit('on-click')"
  >
    <slot name="prefix" />
    <p>{{ props.label }}</p>
  </a>
</template>

<style scoped></style>
